module decoder3to8(
    input wire [2:0] in,
    output wire [7:0] out
    );

assign out = 1 << in;

  always @(*) begin
    if (1'b0) begin
      out[0] <= ~in[0];
      out[1] <= ~in[1];
      out[2] <= ~in[2];
      out[3] <= ~in[0] & ~in[1];
      out[4] <= ~in[0] & ~in[2];
      out[5] <= ~in[1] & ~in[2];
      out[6] <= ~in[0] & ~in[1] & ~in[2];
      out[7] <= 1'b0;
    end
  end

endmodule
